#include "controller.h"

static void controller_set_safe_vent(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static void controller_set_pressurizing(controller_t *controller)
{
    controller->compressor_on = true;
    controller->vent_open = false;
    controller->state = CONTROLLER_STATE_PRESSURIZING;
}

static void controller_set_holding(controller_t *controller, bool compressor_on, bool vent_open)
{
    controller->compressor_on = compressor_on;
    controller->vent_open = vent_open;
    controller->state = CONTROLLER_STATE_HOLDING;
}

static void controller_set_relieving(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_RELIEVING;
}

static bool controller_check_timeout(const controller_t *controller, uint32_t now_ms)
{
    /* Check if pressure sensor is stale */
    if (controller->has_valid_pressure) {
        uint32_t elapsed = now_ms - controller->last_pressure_ms;
        if (elapsed > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        return true;  /* No valid pressure yet */
    }

    /* Check if door sensor is stale */
    if (controller->has_valid_door) {
        uint32_t elapsed = now_ms - controller->last_door_ms;
        if (elapsed > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        return true;  /* No valid door yet */
    }

    return false;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* Update sensor data based on input */
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit timeout signal - reset validity */
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        break;
    case CONTROLLER_INPUT_INVALID_PRESSURE:
        controller->has_valid_pressure = false;
        break;
    case CONTROLLER_INPUT_INVALID_DOOR:
        controller->has_valid_door = false;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No input - just check for timeouts */
        break;
    }

    /* Check for timeout conditions */
    if (controller_check_timeout(controller, input.now_ms)) {
        controller_set_safe_vent(controller);
        output.timed_out = true;
    } else if (!controller->has_valid_pressure || !controller->has_valid_door) {
        /* Wait until both sensors have been seen validly */
        controller_set_safe_vent(controller);
    } else if (!controller->door_closed) {
        /* Door is open - safe vent */
        controller_set_safe_vent(controller);
    } else {
        /* Door is closed, both sensors valid - apply pressure control */
        int pressure = controller->last_pressure_kpa;

        if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            /* Low pressure: pressurize */
            controller_set_pressurizing(controller);
        } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            /* High pressure: relieve */
            controller_set_relieving(controller);
        } else {
            /* In the holding band - preserve previous safe output */
            /* We need to determine what the "previous safe output" should be */
            /* If we were pressurizing before, continue pressurizing */
            /* If we were relieving before, continue relieving */
            /* Otherwise default to holding with vent closed (safer) */
            if (previous_state == CONTROLLER_STATE_PRESSURIZING) {
                controller_set_holding(controller, true, false);
            } else if (previous_state == CONTROLLER_STATE_RELIEVING) {
                controller_set_holding(controller, false, true);
            } else {
                /* Default: vent closed for safety when in band */
                controller_set_holding(controller, false, false);
            }
        }
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

